// modal
class Modal {
	constructor(options) {

		let defaultOptions = {
			isBefore: () => {},
			isOpen: () => {},
			isClose: () => {},
		}
		this.options = Object.assign(defaultOptions, options);
		this.speed = false;
		this.animation = false;
		this.isOpen = false;
		this.modalContainer = false;
		this.previousActiveElement = false;
		this.fixBlocks = document.querySelectorAll('.fix-block');
		this.events();
	}

	events() {
		document.addEventListener('click', function(e){
			const clickedElement = e.target.closest('[data-path]');

			if (clickedElement) {
				this.clickedElement = clickedElement;
				this.target = clickedElement.dataset.path;
				if(this.target === 'calendar') {
					this.getCalendar();
				} else {
					this.getModal();
				}
				this.modal = document.querySelector(`[data-target="${this.target}"]`).parentElement;
				let animation = clickedElement.dataset.animation;
				let speed = clickedElement.dataset.speed;
				let isBef = clickedElement.dataset.before;
				this.animation = animation ? animation : 'fade';
				this.speed = speed ? parseInt(speed) : 300;
				this.modalContainer = document.querySelector(`[data-target="${this.target}"]`);

				this.options.isBefore(clickedElement, this.modalContainer);

				this.open();
				return;
			}

			if (e.target.closest('.modal-popup__close')) {
				this.close(e);
				return;
			}

		}.bind(this));

		window.addEventListener('keydown', function(e) {
			if (e.keyCode == 27) {
				if (this.isOpen) {
					this.close();
				}
			}

			if (e.keyCode == 9 && this.isOpen) {
				this.focusCatch(e);
				return;
			}

		}.bind(this));

		document.addEventListener('click', function(e) {
			if (!e.target.classList.contains('modal-popup__container') && !e.target.closest('.modal-popup__container') && this.isOpen) {
				this.close(e);
			}
		}.bind(this));
	}

	getModal() {
		let overlay = '';
		let upload = this.clickedElement.dataset.upload;
		if (upload) {
			overlay = `
				<div class="modal-popup">
			      <div class="modal-popup__container" data-target="first">
			        <div class="modal-popup__content modal-content-first">
							${upload}		
			        </div>
			      </div>
			    </div>
			`
		} else {
			overlay = `
				<div class="modal-popup">
			      <div class="modal-popup__container" data-target="first">
			        <div class="modal-popup__close">×</div>
			        <div class="modal-popup__content modal-content-first">
			          <div class="modal-content-first__title">ЗАБРОНИРОВАТЬ</div>
			        </div>
			      </div>
			    </div>
			`
		}

		document.body.insertAdjacentHTML('beforeend', overlay)
	}

	getCalendar() {
		let overlay = `
						<div class="modal-popup is-open">
						    <div class="modal-popup__container" data-target="calendar">
						        <div class="modal-popup__close">×</div>
						        <div class="modal-popup__content">
						        
						        <div class="calendar">
							        <div class="month">
							          <svg class="prev" viewbox="0 0 60 100">
							            <path d="M 50,0 L 60,10 L 20,50 L 60,90 L 50,100 L 0,50 Z"></path>
							          </svg>
							          <div class="date">
							            <h1></h1>
							            <p></p>
							          </div>
							          <svg class="next" viewbox="0 0 60 100">
							            <path d="M 50,0 L 60,10 L 20,50 L 60,90 L 50,100 L 0,50 Z"></path>
							          </svg>
							        </div>
							        <div class="weekdays">
							          <div>Пон</div>
							          <div>Вт</div>
							          <div>Ср</div>
							          <div>Чет</div>
							          <div>Пят</div>
							          <div>Суб</div>
							          <div>Вос</div>
							        </div>
							        <div class="days"></div>
							      </div>
						        </div>
						        
						    </div>
						</div>
					`
		document.body.insertAdjacentHTML('beforeend', overlay)

		// строим календарь
		const date = new Date();
		const renderCalendar = () => {
			date.setDate(1);

			const monthDays = document.querySelector(".days");

			const lastDay = new Date(
				date.getFullYear(),
				date.getMonth() + 1,
				0
			).getDate();

			const prevLastDay = new Date(
				date.getFullYear(),
				date.getMonth(),
				0
			).getDate();

			const firstDayIndex = date.getDay() - 1;

			if (date.getMonth() == 7) {
				var lastDayIndex = new Date(
					date.getFullYear(),
					date.getMonth() + 1,
					0
				).getDay();
			} else {
				var lastDayIndex = new Date(
					date.getFullYear(),
					date.getMonth(),
					0
				).getDay();
			}

			const nextDays = 7 - lastDayIndex - 1;

			const months = [
				"Январь",
				"Февраль",
				"Март",
				"Апрель",
				"Май",
				"Июнь",
				"Июль",
				"Август",
				"Сетябрь",
				"Октябрь",
				"Ноябрь",
				"Декабрь",
			];

			document.querySelector(".date h1").innerHTML = months[date.getMonth()];

			const carrentSelect = document.querySelector(".date p")
			carrentSelect.innerHTML = "Дата:  " + (new Date().getDate() + 1) + '.' +(new Date().getMonth() + 1) +'.' + new Date().getFullYear()
			carrentSelect.setAttribute('data-date', date.getMonth() + 1 + '.' + date.getFullYear())


			let pricePage = document.querySelector(".price")

			if(pricePage) {
				carrentSelect.innerHTML = "Дата передачи " + (new Date().getDate() + 1) + '.' +(new Date().getMonth() + 1) +'.' + new Date().getFullYear()

				let calendarPrev = document.querySelector(".calendar .prev")
				if (new Date().getMonth() + 1 < date.getMonth() + 1 || new Date().getFullYear() < date.getFullYear() ) {
					calendarPrev.style.opacity = 1
				} else {
					calendarPrev.style.opacity = 0
				}
			}







			let days = "";

			for (let x = firstDayIndex; x > 0; x--) {
				days += `<div class="prev-date">${prevLastDay - x + 1}</div>`;
			}

			for (let i = 1; i <= lastDay; i++) {
				if (
					i === new Date().getDate() &&
					date.getMonth() === new Date().getMonth()
				) {
					days += `<div class="today">${i}</div>`;
				} else {

					if (
						((i < new Date().getDate() && date.getMonth() === new Date().getMonth()) ||
							(date.getMonth() < new Date().getMonth())) && date.getFullYear() <= new Date().getFullYear()
					)
					{
						if(pricePage) {
							days += `<div class="prev-date">${i}</div>`;
						} else {
							days += `<div class="calendar__date">${i}</div>`;
						}

					} else {
						days += `<div class="calendar__date">${i}</div>`;
					}

				}
			}

			for (let j = 1; j <= nextDays; j++) {
				days += `<div class="next-date">${j}</div>`;
				monthDays.innerHTML = days;
			}
		};
		renderCalendar();

		// выбор даты
		document.querySelector(".days").addEventListener("click", (e) => {
			let element = e.target;
			console.log(element)

			if (element.classList.contains('calendar__date')) {

				let selectMonthYear = document.querySelector(".date p").getAttribute('data-date')
				let selectData = element.textContent+'.'+selectMonthYear

				console.log(selectData);
				document.querySelector("*[data-path='calendar']").value = selectData
				document.querySelector("*[data-date]").textContent = `Выбранная дата: ${selectData}`
				this.close();





			}


		});

		document.querySelector(".prev").addEventListener("click", () => {
			date.setMonth(date.getMonth() - 1);
			renderCalendar();
		});

		document.querySelector(".next").addEventListener("click", () => {
			date.setMonth(date.getMonth() + 1);
			renderCalendar();
		});



	}

	open() {
		this.previousActiveElement = document.activeElement;
		this.modal.style.setProperty('--transition-time', `${this.speed / 1000}s`); // устанавливаем скорость анимации
		this.modal.classList.add('is-open');
		this.disableScroll();

		this.modalContainer.classList.add('modal-popup-open');
		this.modalContainer.classList.add(this.animation); // устанавливаем анимацию

		setTimeout(() => {
			this.options.isOpen(this);
			this.modalContainer.classList.add('animate-open');
			this.isOpen = true;
			this.focusTrap();
		}, this.speed);
	}

	close(e) {
		if (this.modalContainer) {
			this.modalContainer.classList.remove('animate-open');
			this.modalContainer.classList.remove(this.animation);
			this.modal.classList.remove('is-open');
			this.modalContainer.classList.remove('modal-popup-open');


			this.enableScroll();
			this.options.isClose(this);
			this.isOpen = false;
			this.focusTrap();

			var modals = document.querySelectorAll(".modal-popup");
			var modalClose = modals[modals.length-1];

			setTimeout(() => {
				document.body.removeChild(modalClose)
			}, this.speed)
		}
	}

	focusCatch(e) {
		const focusable = this.modalContainer.querySelectorAll(this.focusElements);
		const focusArray = Array.prototype.slice.call(focusable);
		const focusedIndex = focusArray.indexOf(document.activeElement);

		if (e.shiftKey && focusedIndex === 0) {
			focusArray[focusArray.length - 1].focus();
			e.preventDefault();
		}

		if (!e.shiftKey && focusedIndex === focusArray.length - 1) {
			focusArray[0].focus();
			e.preventDefault();
		}
	}

	focusTrap() {

	}

	disableScroll() {
		let pagePosition = window.scrollY;
		this.lockPadding();
		document.body.classList.add('disable-scroll');
		document.body.dataset.position = pagePosition;
		document.body.style.top = -pagePosition + 'px';
	}

	enableScroll() {
		let pagePosition = parseInt(document.body.dataset.position, 10);
		this.unlockPadding();
		document.body.style.top = 'auto';
		document.body.classList.remove('disable-scroll');
		window.scroll({ top: pagePosition, left: 0 });
		document.body.removeAttribute('data-position');
	}

	lockPadding() {
		let paddingOffset = window.innerWidth - document.body.offsetWidth + 'px';
		this.fixBlocks.forEach((el) => {
			el.style.paddingRight = paddingOffset;
		});
		document.body.style.paddingRight = paddingOffset;
	}

	unlockPadding() {
		this.fixBlocks.forEach((el) => {
			el.style.paddingRight = '0px';
		});
		document.body.style.paddingRight = '0px';
	}
}
